-- 1. CRÉATION DE LA TABLE appro_ingredients
CREATE TABLE IF NOT EXISTS appro_ingredients (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    nom TEXT NOT NULL,
    nom_recherche TEXT NOT NULL,
    categorie TEXT,
    unite TEXT DEFAULT 'kg',
    actif BOOLEAN DEFAULT true,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_appro_ingredients_nom_recherche ON appro_ingredients(nom_recherche);
CREATE INDEX IF NOT EXISTS idx_appro_ingredients_actif ON appro_ingredients(actif);
CREATE INDEX IF NOT EXISTS idx_appro_ingredients_categorie ON appro_ingredients(categorie);

-- 2. AJOUT DE LA COLONNE ingredient_id DANS appro_catalogue
ALTER TABLE appro_catalogue ADD COLUMN IF NOT EXISTS ingredient_id UUID REFERENCES appro_ingredients(id);
CREATE INDEX IF NOT EXISTS idx_appro_catalogue_ingredient_id ON appro_catalogue(ingredient_id);

-- 3. AJOUT DE LA COLONNE ingredient_id DANS appro_besoins
ALTER TABLE appro_besoins ADD COLUMN IF NOT EXISTS ingredient_id UUID REFERENCES appro_ingredients(id);
ALTER TABLE appro_besoins ADD COLUMN IF NOT EXISTS ingredient_nom TEXT;
CREATE INDEX IF NOT EXISTS idx_appro_besoins_ingredient_id ON appro_besoins(ingredient_id);

-- 4. NETTOYAGE (au cas où re-exécution)
DELETE FROM appro_ingredients;

